test.config:
searchd
{

}

index rt_local_df
{
	type				= rt
	path				= /rt_local_df
	rt_field			= title
	index_field_lengths	= 1
	index_exact_words	= 1
	morphology			= stem_en
}

queries.sphinxql:
INSERT INTO rt_local_df VALUES
(1, 'runs'),
(2, 'alpha');
FLUSH RAMCHUNK rt_local_df;

INSERT INTO rt_local_df VALUES
(3, 'runs'),
(4, 'beta');
FLUSH RAMCHUNK rt_local_df;


SELECT id, weight() AS w FROM rt_local_df WHERE MATCH('runs') ORDER BY id ASC OPTION ranker=expr('1000000*sum(sum_idf)'), idf='plain,tfidf_unnormalized';
SELECT id, weight() AS w FROM rt_local_df WHERE MATCH('runs') ORDER BY id ASC OPTION ranker=expr('1000000*sum(sum_idf)'), idf='plain,tfidf_unnormalized', local_df=0;



SELECT id, weight() AS w FROM rt_local_df WHERE MATCH('=runs') ORDER BY id ASC OPTION ranker=expr('1000000*sum(sum_idf)'), idf='plain,tfidf_unnormalized';
SELECT id, weight() AS w FROM rt_local_df WHERE MATCH('=runs') ORDER BY id ASC OPTION ranker=expr('1000000*sum(sum_idf)'), idf='plain,tfidf_unnormalized', local_df=0;
